@page "/categories"
@using RecipeShare.Services
@inject RecipeService RecipeService

<PageTitle>Recipe Categories</PageTitle>

<h1>Recipe Categories</h1>
<p>Select a category to browse recipes.</p>

<div class="list-group mt-3">
    @foreach (var category in RecipeService.GetCategories())
    {
        <a href="categories/@category" class="list-group-item list-group-item-action d-flex justify-content-between align-items-center">
            @category
            <span class="badge bg-primary rounded-pill">@RecipeService.GetByCategory(category).Count</span>
        </a>
    }
</div>

@page "/categories/{CategoryName}"
@using RecipeShare.Services
@inject RecipeService RecipeService

<PageTitle>@CategoryName Recipes</PageTitle>

<h1>@CategoryName Recipes</h1>
<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="categories">Categories</a></li>
        <li class="breadcrumb-item active">@CategoryName</li>
    </ol>
</nav>

@if (Recipes.Count == 0)
{
    <p class="text-muted">No recipes found in this category.</p>
}
else
{
    <div class="row">
        @foreach (var recipe in Recipes)
        {
            <div class="col-md-6 mb-3">
                <div class="card h-100">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="card-text">@recipe.Description</p>
                        <p class="text-muted small">
                            @if (recipe.TotalRatings > 0)
                            {
                                <span>★ @recipe.AverageRating.ToString("F1") (@recipe.TotalRatings ratings)</span>
                            }
                            else
                            {
                                <span>No ratings yet</span>
                            }
                        </p>
                        <a href="recipe/@recipe.Id" class="btn btn-outline-primary btn-sm">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter] public string CategoryName { get; set; } = string.Empty;

    private IReadOnlyList<RecipeShare.Models.Recipe> Recipes { get; set; } = [];

    protected override void OnParametersSet()
    {
        Recipes = RecipeService.GetByCategory(CategoryName);
    }
}

@page "/recipe/{Id:int}"
@using RecipeShare.Services
@inject RecipeService RecipeService

<PageTitle>@(Recipe?.Title ?? "Recipe")</PageTitle>

@if (Recipe is null)
{
    <h1>Recipe Not Found</h1>
    <p>The recipe you're looking for doesn't exist.</p>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="categories">Categories</a></li>
            <li class="breadcrumb-item"><a href="categories/@Recipe.Category">@Recipe.Category</a></li>
            <li class="breadcrumb-item active">@Recipe.Title</li>
        </ol>
    </nav>

    <h1>@Recipe.Title</h1>
    <p class="lead">@Recipe.Description</p>

    <div class="mb-4">
        <StarRating RecipeId="Recipe.Id" CurrentAverage="Recipe.AverageRating" TotalRatings="Recipe.TotalRatings" />
    </div>

    <div class="row">
        <div class="col-md-4">
            <div class="card mb-3">
                <div class="card-header"><strong>Ingredients</strong></div>
                <ul class="list-group list-group-flush">
                    @foreach (var ingredient in Recipe.Ingredients)
                    {
                        <li class="list-group-item">@ingredient</li>
                    }
                </ul>
            </div>
        </div>
        <div class="col-md-8">
            <h3>Instructions</h3>
            <ol class="list-group list-group-numbered">
                @foreach (var step in Recipe.Steps)
                {
                    <li class="list-group-item">@step</li>
                }
            </ol>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private RecipeShare.Models.Recipe? Recipe { get; set; }

    protected override void OnParametersSet()
    {
        Recipe = RecipeService.GetById(Id);
    }
}

@rendermode InteractiveServer
@using RecipeShare.Services
@inject RecipeService RecipeService

<div>
    <span class="me-2">
        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <span role="button"
                  style="cursor:pointer; font-size:1.5rem; color:@(star <= (HoverRating ?? SelectedRating ?? 0) ? "#ffc107" : "#dee2e6")"
                  @onclick="() => Rate(star)"
                  @onmouseover="() => HoverRating = star"
                  @onmouseout="() => HoverRating = null">★</span>
        }
    </span>
    @if (Submitted)
    {
        <span class="text-success small">Thanks for rating!</span>
    }
    <span class="text-muted small ms-2">@CurrentAverage.ToString("F1") avg (@TotalRatings ratings)</span>
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double CurrentAverage { get; set; }
    [Parameter] public int TotalRatings { get; set; }

    private int? SelectedRating;
    private int? HoverRating;
    private bool Submitted;

    private void Rate(int stars)
    {
        SelectedRating = stars;
        RecipeService.AddRating(RecipeId, stars);
        var recipe = RecipeService.GetById(RecipeId);
        if (recipe is not null)
        {
            CurrentAverage = recipe.AverageRating;
            TotalRatings = recipe.TotalRatings;
        }
        Submitted = true;
    }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeShare.Models
@using RecipeShare.Services
@inject RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community.</p>

@if (SubmitSuccess)
{
    <div class="alert alert-success">
        <strong>Recipe submitted!</strong> Your recipe has been added.
        <a href="categories/@Submission.Category">View category →</a>
    </div>
}

<EditForm Model="Submission" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
    <DataAnnotationsValidator />

    <div class="mb-3">
        <label class="form-label" for="title">Recipe Title</label>
        <InputText id="title" class="form-control" @bind-Value="Submission.Title" placeholder="e.g., Grandma's Apple Pie" />
    </div>

    <div class="mb-3">
        <label class="form-label" for="category">Category</label>
        <InputSelect id="category" class="form-select" @bind-Value="Submission.Category">
            <option value="">-- Select a category --</option>
            @foreach (var cat in RecipeService.GetCategories())
            {
                <option value="@cat">@cat</option>
            }
            <option value="American">American</option>
            <option value="French">French</option>
            <option value="Japanese">Japanese</option>
            <option value="Other">Other</option>
        </InputSelect>
    </div>

    <div class="mb-3">
        <label class="form-label" for="ingredients">Ingredients (one per line)</label>
        <InputTextArea id="ingredients" class="form-control" rows="6" @bind-Value="Submission.Ingredients"
                       placeholder="2 cups flour&#10;1 cup sugar&#10;3 large apples" />
    </div>

    <div class="mb-3">
        <label class="form-label" for="steps">Steps (one per line)</label>
        <InputTextArea id="steps" class="form-control" rows="6" @bind-Value="Submission.Steps"
                       placeholder="Preheat oven to 350°F&#10;Mix dry ingredients&#10;..." />
    </div>

    <button type="submit" class="btn btn-primary"
            disabled="@(string.IsNullOrWhiteSpace(Submission.Title) || string.IsNullOrWhiteSpace(Submission.Category)
                        || string.IsNullOrWhiteSpace(Submission.Ingredients) || string.IsNullOrWhiteSpace(Submission.Steps))">
        Submit Recipe
    </button>
</EditForm>

@code {
    [SupplyParameterFromForm]
    private RecipeSubmission Submission { get; set; } = new();

    private bool SubmitSuccess;

    private void HandleSubmit()
    {
        if (string.IsNullOrWhiteSpace(Submission.Title) || string.IsNullOrWhiteSpace(Submission.Category))
            return;

        RecipeService.AddRecipe(Submission);
        SubmitSuccess = true;
    }
}

