@using RecipeShare.Models
@using RecipeShare.Services
@inject RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community.</p>

@if (SubmitSuccess)
{
    <div class="alert alert-success">
        <strong>Recipe submitted!</strong> Your recipe has been added.
        <a href="categories/@Submission.Category">View category →</a>
    </div>
}

<EditForm Model="Submission" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
    <DataAnnotationsValidator />

    <div class="mb-3">
        <label class="form-label" for="title">Recipe Title</label>
        <InputText id="title" class="form-control" @bind-Value="Submission.Title" placeholder="e.g., Grandma's Apple Pie" />
    </div>

    <div class="mb-3">
        <label class="form-label" for="category">Category</label>
        <InputSelect id="category" class="form-select" @bind-Value="Submission.Category">
            <option value="">-- Select a category --</option>
            @foreach (var cat in RecipeService.GetCategories())
            {
                <option value="@cat">@cat</option>
            }
            <option value="American">American</option>
            <option value="French">French</option>
            <option value="Japanese">Japanese</option>
            <option value="Other">Other</option>
        </InputSelect>
    </div>

    <div class="mb-3">
        <label class="form-label" for="ingredients">Ingredients (one per line)</label>
        <InputTextArea id="ingredients" class="form-control" rows="6" @bind-Value="Submission.Ingredients"
                       placeholder="2 cups flour&#10;1 cup sugar&#10;3 large apples" />
    </div>

    <div class="mb-3">
        <label class="form-label" for="steps">Steps (one per line)</label>
        <InputTextArea id="steps" class="form-control" rows="6" @bind-Value="Submission.Steps"
                       placeholder="Preheat oven to 350°F&#10;Mix dry ingredients&#10;..." />
    </div>

    <button type="submit" class="btn btn-primary"
            disabled="@(string.IsNullOrWhiteSpace(Submission.Title) || string.IsNullOrWhiteSpace(Submission.Category)
                        || string.IsNullOrWhiteSpace(Submission.Ingredients) || string.IsNullOrWhiteSpace(Submission.Steps))">
        Submit Recipe
    </button>
</EditForm>

@code {
    [SupplyParameterFromForm]
    private RecipeSubmission Submission { get; set; } = new();

    private bool SubmitSuccess;

    private void HandleSubmit()
    {
        if (string.IsNullOrWhiteSpace(Submission.Title) || string.IsNullOrWhiteSpace(Submission.Category))
            return;

        RecipeService.AddRecipe(Submission);
        SubmitSuccess = true;
    }
}
